function openCode(e){const t=document.getElementById('codeModal'),o=document.getElementById('modalTitle'),a=document.getElementById('codeBlock');o.innerText=e,a.innerText='⏳ Carregando código...',e.endsWith('.jsx')?a.className='language-jsx':a.className='language-python',fetch(e).then(e=>{if(!e.ok)throw new Error('Arquivo não encontrado');return e.text()}).then(e=>{a.innerText=e,'undefined'!=typeof Prism&&Prism.highlightElement(a)}).catch(e=>{a.innerText='⚠️ ERRO: '+e.message}),t.classList.add('show'),t.setAttribute('aria-hidden','false')}function closeCode(){const e=document.getElementById('codeModal');e.classList.remove('show'),e.setAttribute('aria-hidden','true')}document.addEventListener('DOMContentLoaded',()=>{const e=document.getElementById('codeModal');e&&(e.addEventListener('click',e=>{e.target===e.currentTarget&&closeCode()}),document.addEventListener('keydown',e=>{'Escape'===e.key&&closeCode()}))});